exercises.solution_code:
class WithdrawalError(Exception):
    """Raised when an account cannot satisfy a withdrawal."""


def withdraw(balance, amount):
    # Validate, then raise a specific, message-bearing error on failure.
    if amount <= 0:
        raise WithdrawalError("amount must be positive")
    if amount > balance:
        raise WithdrawalError(f"insufficient funds: balance {balance}, requested {amount}")
    return balance - amount

class ConfigError(Exception):
    """Raised when a config value cannot be parsed."""


def load_port(config):
    # Wrap a low-level error in a domain error, preserving the original as
    # __cause__ via `raise ... from` so the root cause is not lost.
    try:
        raw = config["port"]
    except KeyError as exc:
        raise ConfigError("missing 'port' in config") from exc
    try:
        return int(raw)
    except ValueError as exc:
        raise ConfigError(f"invalid port: {raw!r}") from exc
